const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
const statusBar = document.getElementById('status-bar');
const onlineCounter = document.getElementById('online-counter');

// Экраны
const startScreen = document.getElementById('start-screen');
const menuScreen = document.getElementById('menu-screen');
const offlineMenuScreen = document.getElementById('offline-menu-screen');
const errorScreen = document.getElementById('error-screen');

// Элементы управления
const loader = document.getElementById('connection-loader');
const connStatus = document.getElementById('connection-status');
const roomListEl = document.getElementById('room-list');
const globalNickInput = document.getElementById('globalNicknameInput');
const roomNameInput = document.getElementById('roomNameInput');

// Константы сервера
const isLocal = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1';
const SERVER_URL = isLocal ? 'http://localhost:3000' : 'https://rgp-game.onrender.com';

// Состояние
let socket = null;
let mode = 'none'; // 'online' | 'offline'
let inGame = false;
let players = {};
const keys = { up: false, down: false, left: false, right: false };
let localPlayerId = 'local_hero';

// --- ЛОГИКА НИКА ---
// Загрузка
if (localStorage.getItem('playerNickname')) {
    globalNickInput.value = localStorage.getItem('playerNickname');
} else {
    globalNickInput.value = "Player_" + Math.floor(Math.random()*1000);
}

// Валидация (только англ буквы, цифры и _)
globalNickInput.addEventListener('input', (e) => {
    const val = e.target.value;
    // Заменяем все, что НЕ (a-z, A-Z, 0-9, _)
    const cleanVal = val.replace(/[^a-zA-Z0-9_]/g, '');

    if (val !== cleanVal) {
        e.target.value = cleanVal;
    }
    localStorage.setItem('playerNickname', cleanVal);
});

function getNickname() {
    return globalNickInput.value || "Player";
}

// --- УПРАВЛЕНИЕ ЭКРАНАМИ ---

function showScreen(screen) {
    document.querySelectorAll('.screen').forEach(el => el.classList.remove('active'));
    screen.classList.add('active');
}

function resetToStart() {
    if (socket) {
        socket.disconnect();
        socket = null;
    }
    inGame = false;
    canvas.style.display = 'none';
    onlineCounter.style.display = 'none';
    statusBar.style.display = 'none';
    players = {};
    connStatus.textContent = '';
    showScreen(startScreen);

    // Показываем инпут ника в главном меню
    document.getElementById('nickname-container').style.display = 'flex';
}

// --- ОНЛАЙН РЕЖИМ ---

window.selectOnline = function() {
    mode = 'online';
    loader.style.display = 'block';
    connStatus.textContent = "Подключение к серверу...";

    socket = io(SERVER_URL, {
        transports: ['websocket', 'polling'],
        reconnection: true,
        reconnectionAttempts: 1, // +1 изначальная = 2 попытки
        reconnectionDelay: 1000,
        timeout: 5000
    });

    socket.on('connect', () => {
        loader.style.display = 'none';
        connStatus.textContent = "";
        showScreen(menuScreen);
        onlineCounter.style.display = 'block';
        statusBar.style.display = 'none';
    });

    let attempt = 1;
    socket.io.on("reconnect_attempt", () => {
        attempt++;
        connStatus.textContent = `Попытка подключения ${attempt}/2...`;
    });

    socket.on('connect_error', (err) => {
        console.log("Connect error", err);
    });

    socket.io.on("reconnect_failed", () => {
        showError("Сервер недоступен. Попробуйте позже.");
    });

    socket.on('onlineCount', (count) => {
        onlineCounter.textContent = `Online: ${count}`;
    });

    socket.on('roomList', renderRoomList);

    socket.on('gameStart', (initialPlayers) => {
        players = initialPlayers;
        startGameUI();
    });

    socket.on('state', (serverPlayers) => {
        players = serverPlayers;
    });

    socket.on('disconnect', (reason) => {
        if (inGame) {
            alert('Потеряно соединение с сервером');
            resetToStart();
        }
    });
}

