let players = {};
const keys = { up: false, down: false, left: false, right: false };
let localPlayerId = 'local_hero';

// --- ИНИЦИАЛИЗАЦИЯ НИКНЕЙМА ---
function initializeNickname() {
    if (localStorage.getItem('playerNickname')) {
        globalNickInput.value = localStorage.getItem('playerNickname');
    } else {
        globalNickInput.value = "Player_" + Math.floor(Math.random() * 1000);
    }

    globalNickInput.addEventListener('input', (e) => {
        const target = e.target;
        const val = target.value;
        const cleanVal = val.replace(/[^a-zA-Z0-9_]/g, '');
        if (val !== cleanVal) {
            target.value = cleanVal;
        }
        localStorage.setItem('playerNickname', cleanVal);
    });
}

function getNickname() {
    return globalNickInput.value || "Player";
}

// --- УПРАВЛЕНИЕ ЭКРАНАМИ ---
function showScreen(screen) {
    document.querySelectorAll('.screen').forEach(el => el.classList.remove('active'));
    screen.classList.add('active');
}

function resetToStart() {
    if (socket) {
        socket.disconnect();
        socket = null;
    }
    inGame = false;
    canvas.style.display = 'none';
    onlineCounter.style.display = 'none';
    statusBar.style.display = 'none';
    statusBar.textContent = '';
    players = {};
    connStatus.textContent = '';
    showScreen(startScreen);
    document.getElementById('nickname-container').style.display = 'flex';
}

// --- ОНЛАЙН РЕЖИМ ---
function selectOnline() {
    mode = 'online';
    loader.style.display = 'block';
    connStatus.textContent = "Подключение к серверу...";

    socket = io(SERVER_URL, {
        transports: ['websocket', 'polling'],
        reconnection: true,
        reconnectionAttempts: 1,
        reconnectionDelay: 1000,
        timeout: 5000
    });

    socket.on('connect', () => {
        loader.style.display = 'none';
        connStatus.textContent = "";
        showScreen(menuScreen);
        onlineCounter.style.display = 'block';
        statusBar.style.display = 'none';
    });

    let attempt = 1;
    socket.io.on("reconnect_attempt", () => {
        attempt++;
        connStatus.textContent = `Попытка подключения ${attempt}/2...`;
    });

    socket.on('connect_error', (err) => console.log("Connect error", err));

    socket.io.on("reconnect_failed", () => showError("Сервер недоступен. Попробуйте позже."));

    socket.on('onlineCount', (count) => (onlineCounter.textContent = `Online: ${count}`));

    socket.on('roomList', renderRoomList);

    socket.on('gameStart', (initialPlayers) => {
        players = initialPlayers;
        startGameUI();
    });

    socket.on('state', (serverPlayers) => (players = serverPlayers));

    socket.on('disconnect', (reason) => {
        if (inGame) {
            alert('Потеряно соединение с сервером');
            resetToStart();
        }
    });
}

function showError(msg) {
    errorScreen.style.display = 'flex';
    document.getElementById('error-details').textContent = msg;
    loader.style.display = 'none';
}

// --- ОФЛАЙН РЕЖИМ ---
function selectOffline() {
    mode = 'offline';
    showScreen(offlineMenuScreen);
}

function startOfflineGame() {
    const nick = getNickname();
    players = {};
    players[localPlayerId] = {
        id: localPlayerId,
        x: 400,
        y: 300,
        color: '#42a5f5',
        nickname: nick
    };
    startGameUI();
}

// --- ОБЩАЯ ЛОГИКА ИГРЫ ---
function startGameUI() {
    inGame = true;
    document.querySelectorAll('.screen').forEach(el => el.classList.remove('active'));
    document.getElementById('nickname-container').style.display = 'none';
    canvas.style.display = 'block';
    statusBar.style.display = 'block';
    statusBar.textContent = mode === 'online' ? "Online Mode" : "Single Player";
    canvas.focus();
    requestAnimationFrame(gameLoop);
}

function createRoom() {
    if (!socket) return;
    const name = roomNameInput.value.trim();
    const nickname = getNickname();
    socket.emit('createRoom', name, nickname);
}

function joinRoom(roomId) {
    if (!socket) return;
    const nickname = getNickname();
    socket.emit('joinRoom', roomId, nickname);
}

function renderRoomList(rooms) {
    roomListEl.innerHTML = '';
    if (rooms.length === 0) {
        roomListEl.innerHTML = '<div style="color: #8d6e63; padding: 15px;">Нет комнат</div>';
        return;
    }

    rooms.forEach(room => {
        const div = document.createElement('div');
        div.className = 'room-item';
        div.innerHTML = `
            <span class="room-info">${room.name}</span>
            <span class="room-count">Игроков: ${room.players}</span>
        `;
        div.addEventListener('click', () => joinRoom(room.id));
        roomListEl.appendChild(div);
    });
}

// --- ИГРОВОЙ ЦИКЛ ---
function updateOfflinePhysics() {
    const p = players[localPlayerId];
    if (!p) return;

    const SPEED = 5;
    const PLAYER_RADIUS = 20;

    if (keys.left) p.x -= SPEED;
    if (keys.up) p.y -= SPEED;
    if (keys.right) p.x += SPEED;
    if (keys.down) p.y += SPEED;

    p.x = Math.max(PLAYER_RADIUS, Math.min(canvas.width - PLAYER_RADIUS, p.x));
    p.y = Math.max(PLAYER_RADIUS, Math.min(canvas.height - PLAYER_RADIUS, p.y));
}

function gameLoop() {
    if (!inGame || !ctx) return;

    if (mode === 'online' && socket) {
        socket.emit('movement', keys);
    } else if (mode === 'offline') {
        updateOfflinePhysics();
    }

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Сетка
    ctx.strokeStyle = 'rgba(0, 0, 0, 0.1)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (let x = 0; x <= canvas.width; x += 50) {
        ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height);
    }
    for (let y = 0; y <= canvas.height; y += 50) {
        ctx.moveTo(0, y); ctx.lineTo(canvas.width, y);
    }
    ctx.stroke();

    // Игроки
    for (let id in players) {
        const p = players[id];
        const isMe = (mode === 'online' && socket && id === socket.id) || (mode === 'offline' && id === localPlayerId);

        // Тень
        ctx.beginPath();
        ctx.ellipse(p.x, p.y + 18, 16, 8, 0, 0, Math.PI * 2);
        ctx.fillStyle = 'rgba(0,0,0,0.3)';
        ctx.fill();

        // Тело
        ctx.beginPath();
        ctx.arc(p.x, p.y, 20, 0, Math.PI * 2);
        ctx.fillStyle = p.color;
        ctx.fill();

        // Обводка
        ctx.lineWidth = isMe ? 4 : 2;
        ctx.strokeStyle = '#fff';
        ctx.stroke();
        if (isMe) {
            ctx.strokeStyle = '#ffd700';
            ctx.stroke();
        }

        // Никнейм
        ctx.font = isMe ? 'bold 16px Verdana' : '14px Verdana';
        ctx.textAlign = 'center';
        ctx.lineWidth = 3;
        ctx.strokeStyle = 'black';
        ctx.strokeText(p.nickname, p.x, p.y - 35);
        ctx.fillStyle = isMe ? '#ffd700' : 'white';
        ctx.fillText(p.nickname, p.x, p.y - 35);
    }

    requestAnimationFrame(gameLoop);
}

// --- ОБРАБОТЧИКИ СОБЫТИЙ ---
function setupEventListeners() {
    // Кнопки меню
    document.getElementById('btn-online').addEventListener('click', selectOnline);
    document.getElementById('btn-offline').addEventListener('click', selectOffline);
    document.getElementById('btn-create-room').addEventListener('click', createRoom);
    document.getElementById('btn-start-offline').addEventListener('click', startOfflineGame);
    document.getElementById('btn-reload').addEventListener('click', () => location.reload());

    document.querySelectorAll('.btn-back').forEach(btn => {
        btn.addEventListener('click', resetToStart);
    });

    // Управление
    window.addEventListener('keydown', (e) => {
        if (!inGame || e.repeat) return;
        if (e.code === 'KeyW' || e.code === 'ArrowUp') keys.up = true;
        if (e.code === 'KeyS' || e.code === 'ArrowDown') keys.down = true;
        if (e.code === 'KeyA' || e.code === 'ArrowLeft') keys.left = true;
        if (e.code === 'KeyD' || e.code === 'ArrowRight') keys.right = true;
    });

    window.addEventListener('keyup', (e) => {
        if (e.code === 'KeyW' || e.code === 'ArrowUp') keys.up = false;
        if (e.code === 'KeyS' || e.code === 'ArrowDown') keys.down = false;
        if (e.code === 'KeyA' || e.code === 'ArrowLeft') keys.left = false;
        if (e.code === 'KeyD' || e.code === 'ArrowRight') keys.right = false;
    });

    // Выход по Escape
    window.addEventListener('keydown', (e) => {
        if (e.code === 'Escape' && inGame) {
            resetToStart();
        }
    });
}

// --- ЗАПУСК ---
document.addEventListener('DOMContentLoaded', () => {
    initializeNickname();
    setupEventListeners();
});
